package com.maum.backend.service

import com.maum.backend.domain.Follow
import com.maum.backend.domain.User
import com.maum.backend.repository.FollowRepository
import org.assertj.core.api.Assertions.assertThat
import org.junit.jupiter.api.Test
import org.junit.jupiter.api.assertThrows
import org.junit.jupiter.api.extension.ExtendWith
import org.mockito.InjectMocks
import org.mockito.Mock
import org.mockito.Mockito.never
import org.mockito.Mockito.verify
import org.mockito.Mockito.`when`
import org.mockito.junit.jupiter.MockitoExtension
import org.mockito.kotlin.any
import java.time.LocalDateTime

@ExtendWith(MockitoExtension::class)
class UserServiceTest {

    @Mock
    private lateinit var followRepository: FollowRepository

    @InjectMocks
    private lateinit var userService: UserService

    // 테스트용 User 픽스처 헬퍼
    private fun createUser(id: Long, username: String = "user$id"): User {
        val user = User(username = username, nickname = "닉네임$id")
        // reflection을 통해 id 설정 (테스트 전용)
        val idField = User::class.java.getDeclaredField("id")
        idField.isAccessible = true
        idField.set(user, id)
        return user
    }

    // ──────────────────────────────────────
    // follow() 테스트
    // ──────────────────────────────────────

    @Test
    fun `should create follow relationship when valid users provided`() {
        // given
        val follower = createUser(1L)
        val followee = createUser(2L)
        `when`(followRepository.existsByFollowerAndFollowee(follower, followee)).thenReturn(false)

        // when
        userService.follow(follower, followee)

        // then
        verify(followRepository).existsByFollowerAndFollowee(follower, followee)
        verify(followRepository).save(any<Follow>())
    }

    @Test
    fun `should throw AlreadyFollowingException when already following`() {
        // given
        val follower = createUser(1L)
        val followee = createUser(2L)
        `when`(followRepository.existsByFollowerAndFollowee(follower, followee)).thenReturn(true)

        // when & then
        assertThrows<AlreadyFollowingException> {
            userService.follow(follower, followee)
        }
        verify(followRepository, never()).save(any<Follow>())
    }

    @Test
    fun `should throw SelfFollowException when follower and followee are same user`() {
        // given
        val user = createUser(1L)

        // when & then
        assertThrows<SelfFollowException> {
            userService.follow(user, user)
        }
        verify(followRepository, never()).existsByFollowerAndFollowee(any(), any())
        verify(followRepository, never()).save(any<Follow>())
    }

    // ──────────────────────────────────────
    // unfollow() 테스트
    // ──────────────────────────────────────

    @Test
    fun `should delete follow relationship when unfollow called`() {
        // given
        val follower = createUser(1L)
        val followee = createUser(2L)
        val follow = Follow(follower = follower, followee = followee)
        `when`(followRepository.findByFollowerAndFollowee(follower, followee)).thenReturn(follow)

        // when
        userService.unfollow(follower, followee)

        // then
        verify(followRepository).findByFollowerAndFollowee(follower, followee)
        verify(followRepository).delete(follow)
    }

    @Test
    fun `should throw NotFollowingException when follow relationship does not exist`() {
        // given
        val follower = createUser(1L)
        val followee = createUser(2L)
        `when`(followRepository.findByFollowerAndFollowee(follower, followee)).thenReturn(null)

        // when & then
        assertThrows<NotFollowingException> {
            userService.unfollow(follower, followee)
        }
        verify(followRepository, never()).delete(any<Follow>())
    }

    // ──────────────────────────────────────
    // getFollowers() 테스트
    // ──────────────────────────────────────

    @Test
    fun `should return list of users who follow the given user`() {
        // given
        val targetUser = createUser(1L)
        val followerA = createUser(2L)
        val followerB = createUser(3L)
        val follows = listOf(
            Follow(follower = followerA, followee = targetUser),
            Follow(follower = followerB, followee = targetUser)
        )
        `when`(followRepository.findAllByFollowee(targetUser)).thenReturn(follows)

        // when
        val result = userService.getFollowers(targetUser)

        // then
        assertThat(result).hasSize(2)
        assertThat(result).containsExactlyInAnyOrder(followerA, followerB)
        verify(followRepository).findAllByFollowee(targetUser)
    }

    @Test
    fun `should return empty list when user has no followers`() {
        // given
        val targetUser = createUser(1L)
        `when`(followRepository.findAllByFollowee(targetUser)).thenReturn(emptyList())

        // when
        val result = userService.getFollowers(targetUser)

        // then
        assertThat(result).isEmpty()
    }

    // ──────────────────────────────────────
    // getFollowings() 테스트
    // ──────────────────────────────────────

    @Test
    fun `should return list of users that the given user is following`() {
        // given
        val targetUser = createUser(1L)
        val followeeA = createUser(2L)
        val followeeB = createUser(3L)
        val follows = listOf(
            Follow(follower = targetUser, followee = followeeA),
            Follow(follower = targetUser, followee = followeeB)
        )
        `when`(followRepository.findAllByFollower(targetUser)).thenReturn(follows)

        // when
        val result = userService.getFollowings(targetUser)

        // then
        assertThat(result).hasSize(2)
        assertThat(result).containsExactlyInAnyOrder(followeeA, followeeB)
        verify(followRepository).findAllByFollower(targetUser)
    }

    @Test
    fun `should return empty list when user follows nobody`() {
        // given
        val targetUser = createUser(1L)
        `when`(followRepository.findAllByFollower(targetUser)).thenReturn(emptyList())

        // when
        val result = userService.getFollowings(targetUser)

        // then
        assertThat(result).isEmpty()
    }

    // ──────────────────────────────────────
    // isFollowing() 테스트
    // ──────────────────────────────────────

    @Test
    fun `should return true when follower is following followee`() {
        // given
        val follower = createUser(1L)
        val followee = createUser(2L)
        `when`(followRepository.existsByFollowerAndFollowee(follower, followee)).thenReturn(true)

        // when
        val result = userService.isFollowing(follower, followee)

        // then
        assertThat(result).isTrue()
        verify(followRepository).existsByFollowerAndFollowee(follower, followee)
    }

    @Test
    fun `should return false when follower is not following followee`() {
        // given
        val follower = createUser(1L)
        val followee = createUser(2L)
        `when`(followRepository.existsByFollowerAndFollowee(follower, followee)).thenReturn(false)

        // when
        val result = userService.isFollowing(follower, followee)

        // then
        assertThat(result).isFalse()
    }

    @Test
    fun `should return false when checking self following`() {
        // given
        val user = createUser(1L)
        `when`(followRepository.existsByFollowerAndFollowee(user, user)).thenReturn(false)

        // when
        val result = userService.isFollowing(user, user)

        // then
        assertThat(result).isFalse()
    }
}
