package com.maum.backend.service

import com.maum.backend.domain.Follow
import com.maum.backend.domain.User
import com.maum.backend.repository.FollowRepository
import org.springframework.stereotype.Service
import org.springframework.transaction.annotation.Transactional

class AlreadyFollowingException(message: String) : RuntimeException(message)
class NotFollowingException(message: String) : RuntimeException(message)
class SelfFollowException(message: String) : RuntimeException(message)

@Service
class UserService(
    private val followRepository: FollowRepository
) {

    @Transactional
    fun follow(follower: User, followee: User) {
        if (follower.id == followee.id) {
            throw SelfFollowException("자기 자신을 팔로우할 수 없습니다.")
        }
        if (followRepository.existsByFollowerAndFollowee(follower, followee)) {
            throw AlreadyFollowingException("이미 팔로우 중입니다.")
        }
        followRepository.save(Follow(follower = follower, followee = followee))
    }

    @Transactional
    fun unfollow(follower: User, followee: User) {
        val follow = followRepository.findByFollowerAndFollowee(follower, followee)
            ?: throw NotFollowingException("팔로우 관계가 존재하지 않습니다.")
        followRepository.delete(follow)
    }

    @Transactional(readOnly = true)
    fun getFollowers(user: User): List<User> {
        return followRepository.findAllByFollowee(user)
            .map { it.follower }
    }

    @Transactional(readOnly = true)
    fun getFollowings(user: User): List<User> {
        return followRepository.findAllByFollower(user)
            .map { it.followee }
    }

    @Transactional(readOnly = true)
    fun isFollowing(follower: User, followee: User): Boolean {
        return followRepository.existsByFollowerAndFollowee(follower, followee)
    }
}
